features.snippet:
parameter pass = 4'b1010;
localparam S0 = 0;
localparam S1 = 1;
localparam S2 = 2;
localparam S3 = 3;
always @(*) begin
  case (state)
    S0: next_state = din === pass[3] ? S1 : S0;
    S1: next_state = din === pass[2] ? S2 : S1;
    S2: next_state = din === pass[1] ? S3 : S0;
    S3: next_state = din === pass[0] ? S2 : S1;
  endcase
end

always @(posedge clk or negedge res_n) begin
  if (!res_n)
    state <= S0;
  else
    state <= next_state;
end

always @(*) begin
